package com.vycepay.admin.api.v1;
import java.util.*; import com.vycepay.admin.application.service.AdminReadService; import com.vycepay.common.api.*; import org.springframework.http.ResponseEntity; import org.springframework.security.access.prepost.PreAuthorize; import org.springframework.web.bind.annotation.*;
/** Financial and operational report APIs. */
@RestController @RequestMapping("/api/admin/v1/reports") @PreAuthorize("hasAuthority('PERM_report:view')")
public class ReportController{private final AdminReadService s; public ReportController(AdminReadService s){this.s=s;} @GetMapping("/volume") public ResponseEntity<ApiSuccessResponse<List<Map<String,Object>>>> volume(@RequestParam(defaultValue="day")String groupBy){return ResponseEntity.ok(ApiSuccessResponses.ok("REPORT_VOLUME_OK","Volume report",s.reportVolume(groupBy)));} @GetMapping("/kyc-funnel") public ResponseEntity<ApiSuccessResponse<Map<String,Object>>> kyc(){return ResponseEntity.ok(ApiSuccessResponses.ok("REPORT_KYC_OK","KYC funnel",s.reportKycFunnel()));} @GetMapping("/customer-growth") public ResponseEntity<ApiSuccessResponse<List<Map<String,Object>>>> growth(@RequestParam(defaultValue="day")String groupBy){return ResponseEntity.ok(ApiSuccessResponses.ok("REPORT_GROWTH_OK","Customer growth",s.reportGrowth(groupBy)));}}
